class FrameworkTestComponent extends(FrameworkGC(`${injector_html}`)){constructor(t){super(t),this.#t(t),this.#e(t),this.test()}async#t(t){}async#e(t){}async test(){const t=UiBuilder.createButton({title:"Test Button",onClick:()=>{alert("Button Clicked!")}});this.self_ref.appendChild(t);const e=this.self_ref.querySelector(".list-icons");for(let t=61202;t<61212;t++)try{const n=t.toString(16).padStart(4,"0"),i=document.createElement("div");i.classList.add("card"),i.style="width: fit-content;height: fit-content;min-width: unset;min-height: unset;border: 1px solid;padding: 4px;";const s=document.createElement("div");s.innerText=`&#x${n};`,s.style.userSelect="all",i.appendChild(s),i.appendChild(FrameworkTestComponent.ezIcon(n)),e.appendChild(i)}catch(t){break}}static ezIcon(t){const e=document.createElement("div");e.classList.add("f-icon");const n=String.fromCodePoint(parseInt(t,16));return e.setAttribute("data-icon",n),e}}setTimeout((()=>{if(null==window.the_main_app){const t=new FrameworkTestComponent({});document.body.appendChild(t.self_ref)}}),0);